const messages=document.getElementById("messages"),fetchPromptButton=document.getElementById("fetchPrompt"),replyForm=document.getElementById("replyForm"),responseInput=document.getElementById("response"),chatHistory=[{role:"server",text:"Ready to fetch the latest prompt from getprompt."}];function createMessage(e,t){const s=document.createElement("div");s.className=`message ${e}`,s.setAttribute("data-role","ai"===e?"AI":"SERVER");const r=document.createElement("p");return r.textContent=t,s.appendChild(r),s}function renderMessages(){messages.innerHTML="",chatHistory.forEach(({role:e,text:t})=>{messages.appendChild(createMessage(e,t))}),messages.scrollTop=messages.scrollHeight}async function fetchPrompt(){fetchPromptButton.disabled=!0,fetchPromptButton.textContent="Fetching...";try{const e=await fetch("getprompt");if(!e.ok)throw new Error(`HTTP ${e.status}`);const t=await e.text();chatHistory.push({role:"server",text:t||"Received empty prompt response."})}catch(e){chatHistory.push({role:"server",text:`Unable to fetch prompt: ${e.message}`})}finally{fetchPromptButton.disabled=!1,fetchPromptButton.textContent="Fetch Prompt",renderMessages()}}replyForm.addEventListener("submit",e=>{e.preventDefault();const t=responseInput.value.trim();t&&(chatHistory.push({role:"ai",text:t}),responseInput.value="",renderMessages())}),fetchPromptButton.addEventListener("click",fetchPrompt),renderMessages();